namespace RecipeShare.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public int TotalRatings { get; set; }
    public int RatingSum { get; set; }

    public double AverageRating => TotalRatings > 0 ? (double)RatingSum / TotalRatings : 0;
}

public class RecipeSubmission
{
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
}

using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;

    public RecipeService()
    {
        _recipes =
        [
            new Recipe
            {
                Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
                Description = "A simple and delicious traditional Margherita pizza with fresh basil.",
                Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
                Steps = [
                    "Preheat oven to 475°F (245°C) with a pizza stone if available.",
                    "Roll out dough on a floured surface into a 12-inch circle.",
                    "Spread crushed tomatoes evenly over the dough, leaving a 1-inch border.",
                    "Tear mozzarella into pieces and distribute over the sauce.",
                    "Bake for 10–12 minutes until crust is golden and cheese is bubbly.",
                    "Top with fresh basil leaves and a drizzle of olive oil before serving."
                ],
                TotalRatings = 12, RatingSum = 52
            },
            new Recipe
            {
                Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
                Description = "Creamy Roman pasta made with eggs, cheese, pancetta, and pepper.",
                Ingredients = ["Spaghetti", "Pancetta", "Eggs", "Pecorino Romano", "Black pepper", "Salt"],
                Steps = [
                    "Cook spaghetti in salted boiling water until al dente.",
                    "While pasta cooks, fry pancetta until crispy.",
                    "Whisk eggs with grated Pecorino and plenty of black pepper.",
                    "Drain pasta, reserving 1 cup of pasta water.",
                    "Toss hot pasta with pancetta, then remove from heat.",
                    "Pour egg mixture over pasta and toss quickly, adding pasta water as needed for a creamy sauce."
                ],
                TotalRatings = 8, RatingSum = 35
            },
            new Recipe
            {
                Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
                Description = "Tender chicken pieces in a rich, spiced tomato-cream sauce.",
                Ingredients = ["Chicken breast", "Yogurt", "Garam masala", "Tomato sauce", "Heavy cream", "Onion", "Garlic", "Ginger", "Cumin", "Turmeric"],
                Steps = [
                    "Marinate chicken in yogurt, garam masala, cumin, and turmeric for at least 1 hour.",
                    "Grill or broil chicken until lightly charred, then cut into pieces.",
                    "Sauté onion, garlic, and ginger until softened.",
                    "Add tomato sauce and spices; simmer for 15 minutes.",
                    "Stir in cream and add the chicken pieces.",
                    "Simmer for 10 minutes. Serve over basmati rice."
                ],
                TotalRatings = 15, RatingSum = 68
            },
            new Recipe
            {
                Id = 4, Title = "Vegetable Pad Thai", Category = "Asian",
                Description = "A vibrant stir-fried noodle dish with crunchy vegetables and tangy sauce.",
                Ingredients = ["Rice noodles", "Tofu", "Bean sprouts", "Carrots", "Green onions", "Peanuts", "Tamarind paste", "Fish sauce", "Lime", "Sugar", "Eggs"],
                Steps = [
                    "Soak rice noodles in warm water for 30 minutes, then drain.",
                    "Mix tamarind paste, fish sauce, sugar, and lime juice for the sauce.",
                    "Press and cube tofu, then fry until golden.",
                    "Scramble eggs in the same pan, then add vegetables and stir-fry.",
                    "Add noodles and sauce; toss until well combined and heated through.",
                    "Serve topped with crushed peanuts, bean sprouts, and lime wedges."
                ],
                TotalRatings = 10, RatingSum = 42
            },
            new Recipe
            {
                Id = 5, Title = "Beef Tacos", Category = "Mexican",
                Description = "Seasoned ground beef tacos with fresh toppings in crispy shells.",
                Ingredients = ["Ground beef", "Taco seasoning", "Taco shells", "Lettuce", "Tomatoes", "Cheddar cheese", "Sour cream", "Salsa"],
                Steps = [
                    "Brown ground beef in a skillet over medium-high heat.",
                    "Drain excess fat and add taco seasoning with a splash of water.",
                    "Simmer for 5 minutes until sauce thickens.",
                    "Warm taco shells according to package directions.",
                    "Fill shells with seasoned beef.",
                    "Top with shredded lettuce, diced tomatoes, cheese, sour cream, and salsa."
                ],
                TotalRatings = 6, RatingSum = 25
            },
            new Recipe
            {
                Id = 6, Title = "Chocolate Lava Cake", Category = "Desserts",
                Description = "Rich, indulgent chocolate cakes with a molten center.",
                Ingredients = ["Dark chocolate", "Butter", "Eggs", "Sugar", "Flour", "Vanilla extract"],
                Steps = [
                    "Preheat oven to 425°F (220°C). Grease and flour four ramekins.",
                    "Melt chocolate and butter together in a double boiler.",
                    "Whisk eggs, egg yolks, and sugar until thick and pale.",
                    "Fold the chocolate mixture into the eggs, then fold in flour.",
                    "Divide batter among ramekins.",
                    "Bake for 12–14 minutes until edges are firm but center is soft. Invert onto plates and serve immediately."
                ],
                TotalRatings = 20, RatingSum = 94
            },
            new Recipe
            {
                Id = 7, Title = "Guacamole", Category = "Mexican",
                Description = "Fresh, creamy guacamole with a kick of lime and cilantro.",
                Ingredients = ["Avocados", "Lime juice", "Cilantro", "Red onion", "Jalapeño", "Tomato", "Salt", "Garlic"],
                Steps = [
                    "Halve and pit avocados; scoop flesh into a bowl.",
                    "Mash with a fork to desired consistency.",
                    "Stir in diced onion, tomato, jalapeño, cilantro, and minced garlic.",
                    "Add lime juice and salt to taste.",
                    "Serve immediately with tortilla chips."
                ],
                TotalRatings = 9, RatingSum = 40
            },
            new Recipe
            {
                Id = 8, Title = "Miso Ramen", Category = "Asian",
                Description = "Hearty Japanese noodle soup with a savory miso broth.",
                Ingredients = ["Ramen noodles", "Miso paste", "Chicken broth", "Soy sauce", "Sesame oil", "Soft-boiled eggs", "Green onions", "Corn", "Nori", "Chashu pork"],
                Steps = [
                    "Bring chicken broth to a simmer. Whisk in miso paste and soy sauce.",
                    "Cook ramen noodles according to package directions.",
                    "Prepare soft-boiled eggs (6–7 minutes in boiling water).",
                    "Slice chashu pork and sear briefly in a hot pan.",
                    "Divide noodles among bowls and ladle broth over them.",
                    "Top with halved eggs, pork, corn, sliced green onions, and nori."
                ],
                TotalRatings = 11, RatingSum = 49
            }
        ];
        _nextId = 9;
    }

    public IReadOnlyList<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().Order().ToList();
    }

    public IReadOnlyList<Recipe> GetByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.TotalRatings++;
            recipe.RatingSum += stars;
        }
    }

    public Recipe AddRecipe(RecipeSubmission submission)
    {
        var recipe = new Recipe
        {
            Id = _nextId++,
            Title = submission.Title,
            Category = submission.Category,
            Description = $"A community-submitted {submission.Category.ToLowerInvariant()} recipe.",
            Ingredients = submission.Ingredients
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList(),
            Steps = submission.Steps
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList()
        };
        _recipes.Add(recipe);
        return recipe;
    }
}

