arguments.file_text:
@page "/category/{CategoryName}"
@using RecipeShare.Services
@inject RecipeService Recipes

<PageTitle>@CategoryName Recipes — RecipeShare</PageTitle>

<h1>@CategoryName Recipes</h1>

@if (recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category.</div>
}
else
{
    <div class="row">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h4 class="card-title">@recipe.Title</h4>
                        <p class="card-text text-muted">@recipe.Description</p>
                        @if (recipe.TotalRatings > 0)
                        {
                            <p class="mb-2">
                                @for (int i = 1; i <= 5; i++)
                                {
                                    <span>@(i <= (int)Math.Round(recipe.AverageRating) ? "★" : "☆")</span>
                                }
                                <small class="text-muted">(@recipe.TotalRatings ratings)</small>
                            </p>
                        }
                        <a href="recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

<a href="/" class="btn btn-link">← Back to Categories</a>

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;

    private IReadOnlyList<RecipeShare.Models.Recipe> recipes = [];

    protected override void OnParametersSet()
    {
        recipes = Recipes.GetByCategory(CategoryName);
    }
}

@page "/recipe/{RecipeId:int}"
@using RecipeShare.Services
@inject RecipeService Recipes

<PageTitle>@(recipe?.Title ?? "Recipe") — RecipeShare</PageTitle>

@if (recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
    <a href="/" class="btn btn-link">← Back to Home</a>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="category/@recipe.Category">@recipe.Category</a></li>
            <li class="breadcrumb-item active">@recipe.Title</li>
        </ol>
    </nav>

    <h1>@recipe.Title</h1>
    <p class="lead text-muted">@recipe.Description</p>

    <StarRating RecipeId="recipe.Id" CurrentAverage="recipe.AverageRating" TotalRatings="recipe.TotalRatings" />

    <div class="row mt-4">
        <div class="col-md-4">
            <div class="card mb-4">
                <div class="card-header"><h5 class="mb-0">🧾 Ingredients</h5></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in recipe.Ingredients)
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>

        <div class="col-md-8">
            <h5>📝 Instructions</h5>
            <ol class="list-group list-group-numbered mb-4">
                @foreach (var step in recipe.Steps)
                {
                    <li class="list-group-item">@step</li>
                }
            </ol>
        </div>
    </div>

    <a href="category/@recipe.Category" class="btn btn-link">← Back to @recipe.Category Recipes</a>
}

@code {
    [Parameter] public int RecipeId { get; set; }

    private RecipeShare.Models.Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = Recipes.GetById(RecipeId);
    }
}

@page "/submit"
@using RecipeShare.Models
@using RecipeShare.Services
@inject RecipeService Recipes
@inject NavigationManager Nav
@rendermode InteractiveServer

<PageTitle>Submit a Recipe — RecipeShare</PageTitle>

<h1>📤 Submit a Recipe</h1>
<p class="text-muted">Share your favorite recipe with the community!</p>

@if (submitted)
{
    <div class="alert alert-success">
        <strong>Thank you!</strong> Your recipe "<strong>@submission.Title</strong>" has been submitted.
        <a href="recipe/@submittedId">View it here</a>.
    </div>
}
else
{
    <EditForm Model="submission" OnValidSubmit="HandleSubmit" FormName="submit-recipe" class="mb-4">
        <DataAnnotationsValidator />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" @bind-Value="submission.Title" class="form-control" placeholder="e.g. Grandma's Apple Pie" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" @bind-Value="submission.Category" class="form-select">
                <option value="">-- Select a category --</option>
                <option value="Italian">Italian</option>
                <option value="Indian">Indian</option>
                <option value="Asian">Asian</option>
                <option value="Mexican">Mexican</option>
                <option value="Desserts">Desserts</option>
                <option value="Other">Other</option>
            </InputSelect>
        </div>

        <div class="mb-3">
