        <strong>Thank you!</strong> Your recipe "<strong>@submission.Title</strong>" has been submitted.
        <a href="recipe/@submittedId">View it here</a>.
    </div>
}
else
{
    <EditForm Model="submission" OnValidSubmit="HandleSubmit" FormName="submit-recipe" class="mb-4">
        <DataAnnotationsValidator />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" @bind-Value="submission.Title" class="form-control" placeholder="e.g. Grandma's Apple Pie" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" @bind-Value="submission.Category" class="form-select">
                <option value="">-- Select a category --</option>
                <option value="Italian">Italian</option>
                <option value="Indian">Indian</option>
                <option value="Asian">Asian</option>
                <option value="Mexican">Mexican</option>
                <option value="Desserts">Desserts</option>
                <option value="Other">Other</option>
            </InputSelect>
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients</label>
            <InputTextArea id="ingredients" @bind-Value="submission.Ingredients" class="form-control" rows="5"
                placeholder="One ingredient per line&#10;e.g.&#10;2 cups flour&#10;1 cup sugar&#10;3 eggs" />
            <div class="form-text">Enter one ingredient per line.</div>
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps</label>
            <InputTextArea id="steps" @bind-Value="submission.Steps" class="form-control" rows="5"
                placeholder="One step per line&#10;e.g.&#10;Preheat oven to 350°F.&#10;Mix dry ingredients together." />
            <div class="form-text">Enter one step per line.</div>
        </div>

        <button type="submit" class="btn btn-success"
                disabled="@(string.IsNullOrWhiteSpace(submission.Title) || string.IsNullOrWhiteSpace(submission.Category) || string.IsNullOrWhiteSpace(submission.Ingredients) || string.IsNullOrWhiteSpace(submission.Steps))">
            Submit Recipe
        </button>
    </EditForm>
}

@code {
    private RecipeSubmission submission = new();
    private bool submitted;
    private int submittedId;

    private void HandleSubmit()
    {
        var recipe = Recipes.AddRecipe(submission);
        submittedId = recipe.Id;
        submitted = true;
    }
}

@using RecipeShare.Services
@inject RecipeService Recipes
@rendermode InteractiveServer

<div class="my-3">
    <span class="me-2" style="font-size: 1.5rem; cursor: pointer;">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span @onclick="() => Rate(star)"
                  @onmouseover="() => hovered = star"
                  @onmouseout="() => hovered = 0"
                  style="color: @(GetStarColor(star))"
                  role="button"
                  title="Rate @star star(s)">★</span>
        }
    </span>

    @if (userRating > 0)
    {
        <span class="badge bg-success">You rated @userRating star(s)</span>
    }
    else
    {
        <span class="text-muted">Click to rate</span>
    }

    <span class="ms-3 text-muted">
        Avg: @displayAverage.ToString("0.0") / 5
        (@displayTotal ratings)
    </span>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentAverage { get; set; }
    [Parameter] public int TotalRatings { get; set; }

    private int hovered;
    private int userRating;
    private double displayAverage;
    private int displayTotal;

    protected override void OnParametersSet()
    {
        displayAverage = CurrentAverage;
        displayTotal = TotalRatings;
    }

    private void Rate(int stars)
    {
        if (userRating > 0) return; // only allow one rating per session
        userRating = stars;
        Recipes.AddRating(RecipeId, stars);
        var recipe = Recipes.GetById(RecipeId);
        if (recipe is not null)
        {
            displayAverage = recipe.AverageRating;
            displayTotal = recipe.TotalRatings;
        }
    }

    private string GetStarColor(int star)
    {
        if (hovered > 0)
            return star <= hovered ? "#ffc107" : "#e0e0e0";
        if (userRating > 0)
            return star <= userRating ? "#ffc107" : "#e0e0e0";
        return star <= (int)Math.Round(displayAverage) ? "#ffc107" : "#e0e0e0";
    }
}

